def spiralOrder(m):
    if not m: return []
    res = []
    r1, r2, c1, c2 = 0, len(m)-1, 0, len(m[0])-1
    while r1<=r2 and c1<=c2:
        for c in range(c1, c2+1): res.append(m[r1][c])
        for r in range(r1+1, r2+1): res.append(m[r][c2])
        if r1<r2 and c1<c2:
            for c in range(c2-1, c1, -1): res.append(m[r2][c])
            for r in range(r2, r1, -1): res.append(m[r][c1])
        r1+=1; r2-=1; c1+=1; c2-=1
    return res

